mapper.update:
UPDATE orders
SET order_status = #{status}
WHERE order_id = #{orderId}

UPDATE user_coupon 
SET is_used = true 
WHERE user_coupon_id = #{userCouponId}

UPDATE users 
SET point_balance = point_balance - #{amount} 
WHERE user_id = #{userId}

UPDATE users 
SET point_balance = point_balance + #{amount} 
WHERE user_id = #{userId}

